framework_css:
:root {
  --color-primary-900: #11161D;
  --color-primary-accent: #8BC53F;
  --color-secondary-cyan: #00AEEF;
  --color-secondary-soft: #EAF7FF;
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F5F5F5;
  --color-neutral-700: #333333;
  --color-neutral-500: #666666;
  --color-semantic-success: #8BC53F;
  --color-semantic-error: #E53935;
  --color-semantic-warning: #FFB300;
  --color-semantic-info: #0288D1;

  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --layout-max-width: 1160px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-700);
  background-color: var(--color-neutral-0);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

img {
  max-width: 100%;
  display: block;
}

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-4);
}

.site-header {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-0);
}

.top-bar {
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  font-size: var(--font-size-small);
}

.top-bar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-2) 0;
}

.top-bar__tagline {
  color: var(--color-secondary-soft);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.top-bar__contacts {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

.top-bar__link {
  display: inline-flex;
  align-items: center;
  color: var(--color-secondary-soft);
}

.top-bar__link:hover {
  color: var(--color-primary-accent);
}

.top-bar__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.4);
  font-size: 10px;
  margin-right: var(--space-1);
}

.top-bar__icon--mail {
  border-color: rgba(139, 197, 63, 0.8);
}

.top-bar__icon--phone {
  border-color: rgba(0, 174, 239, 0.9);
}

.main-nav {
  padding: var(--space-3) 0;
}

.main-nav__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-5);
}

.logo {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-neutral-0);
}

.logo__mark {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  border: 2px solid var(--color-primary-accent);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 16px;
  color: var(--color-primary-accent);
}

.logo__text {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.08em;
  font-size: 16px;
  color: var(--color-secondary-soft);
}

.primary-nav {
  flex: 1 1 auto;
}

.primary-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
}

.primary-nav__item {
  position: relative;
}

.primary-nav__link {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-0);
  padding: var(--space-1) 0;
  transition: color 0.2s ease;
}

.primary-nav__link:hover,
.primary-nav__link:focus {
  color: var(--color-primary-accent);
}

.primary-nav__link--active {
  color: var(--color-primary-accent);
}

.primary-nav__item--has-dropdown .primary-nav__link::after {
  content: '';
  border-left: 4px solid transparent;
  border-right: 4px solid transparent;
  border-top: 4px solid var(--color-neutral-0);
  margin-top: 3px;
}

.primary-nav__item--has-dropdown .primary-nav__link:hover::after,
.primary-nav__item--has-dropdown .primary-nav__link--active::after {
  border-top-color: var(--color-primary-accent);
}

.header-social {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.header-social__icon {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-0);
  background-color: #5f6a75;
  transition: background-color 0.2s ease, transform 0.1s ease;
}

.header-social__icon--video {
  background-color: var(--color-secondary-cyan);
}

.header-social__icon--social {
  background-color: #1877F2;
}

.header-social__icon--more,
.header-social__icon--globe {
  background-color: #4D555E;
}

.header-social__icon:hover {
  transform: translateY(-1px);
  background-color: var(--color-primary-accent);
}

.header-social__label {
  line-height: 1;
}

.breadcrumb {
  background-color: var(--color-secondary-soft);
}

.breadcrumb__inner {
  padding: var(--space-3) 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

.site-main {
  min-height: 60vh;
  padding: var(--space-6) 0;
}

.site-footer {
  background-color: var(--color-primary-900);
  color: var(--color-secondary-soft);
  padding: var(--space-6) 0 var(--space-4);
  font-size: var(--font-size-small);
}

.footer__inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

.footer__top {
  display: grid;
  grid-template-columns: minmax(0, 2.2fr) repeat(4, minmax(0, 1fr));
  gap: var(--space-5);
}

.footer__brand {
  max-width: 320px;
}

.footer-logo .logo__mark {
  width: 36px;
  height: 36px;
}

.footer-logo .logo__text {
  font-size: 15px;
}

.footer__description {
  margin: var(--space-3) 0 0;
  color: var(--color-neutral-500);
  line-height: var(--line-height-relaxed);
}

.footer__column {
  min-width: 0;
}

.footer__heading {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-0);
}

.footer__links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--space-1);
}

.footer__links a {
  color: var(--color-secondary-soft);
}

.footer__links a:hover {
  color: var(--color-primary-accent);
}

.footer__bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: var(--space-3);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
}

.footer__copy {
  margin: 0;
  color: var(--color-neutral-500);
}

.fab-chat {
  position: fixed;
  right: var(--space-4);
  bottom: var(--space-4);
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background-color: var(--color-primary-accent);
  color: var(--color-neutral-0);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 6px 18px rgba(0, 0, 0, 0.3);
  text-decoration: none;
  z-index: 1000;
}

.fab-chat__icon {
  font-size: 28px;
  font-weight: var(--font-weight-bold);
}

.fab-chat:hover {
  background-color: #7ab934;
}

@media (max-width: 960px) {
  .top-bar__inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
  }

  .main-nav__inner {
    flex-wrap: wrap;
    align-items: flex-start;
  }

  .primary-nav__list {
    flex-wrap: wrap;
    justify-content: flex-start;
    row-gap: var(--space-2);
  }

  .footer__top {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 640px) {
  .container {
    padding: 0 var(--space-3);
  }

  .top-bar__contacts {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
  }

  .header-social {
    display: none;
  }

  .footer__top {
    grid-template-columns: 1fr;
  }

  .fab-chat {
    width: 56px;
    height: 56px;
  }
}
